const e=JSON.parse('{"key":"v-08ef6a96","path":"/%E8%AF%81%E5%88%B8%E4%BA%A4%E6%98%93/%E9%81%93%E6%B0%8F%E7%90%86%E8%AE%BA%EF%BC%88%E5%A4%A9%E6%B4%A5%E7%A4%BE%E7%A7%91%E7%89%88%EF%BC%89/04-%E9%81%93%E6%B0%8F%E7%90%86%E8%AE%BA%E5%9B%9B.html","title":"道氏理论四","lang":"zh-CN","frontmatter":{"date":"2024-01-17T00:00:00.000Z","category":["证券交易"],"tag":["道氏理论"],"order":4,"description":"道氏理论四 双重顶和双重底 双重顶和双重底形态，对于判断股票价格走势参考意义不大。实践表明它们时常会给人假象。 汉密尔顿曾经多次指出，根据双重顶或者双重底形态推断市场意义不大。一个有意思的疑问是，到底是谁告诉人们双重顶和双重底形态是道氏理论不可分割的一部分。这一观点甚至在人们心中根深蒂固。 每当接近前期高点或低点，市场上总是充斥着双重顶和双重底形态相关的评论文章，其预测结论注定一无是处。那些文章通常冠以这样的标签：根据道氏理论，假如工业股指数形成双重顶形态，等等。道氏理论的研究者无人不知，单靠一种价格指数得出的结论注定无效。同时，两种指数同时形成双重顶和双重底形态非常罕见，即便是同时出现也纯属巧合。细数一下三十五年以来重要的次级运动，不难发现以双重顶和双重底为标志结束的情况少之又少。","head":[["meta",{"property":"og:url","content":"https://mister-hope.github.io/%E8%AF%81%E5%88%B8%E4%BA%A4%E6%98%93/%E9%81%93%E6%B0%8F%E7%90%86%E8%AE%BA%EF%BC%88%E5%A4%A9%E6%B4%A5%E7%A4%BE%E7%A7%91%E7%89%88%EF%BC%89/04-%E9%81%93%E6%B0%8F%E7%90%86%E8%AE%BA%E5%9B%9B.html"}],["meta",{"property":"og:site_name","content":"Journey of Growth"}],["meta",{"property":"og:title","content":"道氏理论四"}],["meta",{"property":"og:description","content":"道氏理论四 双重顶和双重底 双重顶和双重底形态，对于判断股票价格走势参考意义不大。实践表明它们时常会给人假象。 汉密尔顿曾经多次指出，根据双重顶或者双重底形态推断市场意义不大。一个有意思的疑问是，到底是谁告诉人们双重顶和双重底形态是道氏理论不可分割的一部分。这一观点甚至在人们心中根深蒂固。 每当接近前期高点或低点，市场上总是充斥着双重顶和双重底形态相关的评论文章，其预测结论注定一无是处。那些文章通常冠以这样的标签：根据道氏理论，假如工业股指数形成双重顶形态，等等。道氏理论的研究者无人不知，单靠一种价格指数得出的结论注定无效。同时，两种指数同时形成双重顶和双重底形态非常罕见，即便是同时出现也纯属巧合。细数一下三十五年以来重要的次级运动，不难发现以双重顶和双重底为标志结束的情况少之又少。"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:locale","content":"zh-CN"}],["meta",{"property":"og:updated_time","content":"2024-02-04T15:27:55.000Z"}],["meta",{"property":"article:author","content":"Mr.G"}],["meta",{"property":"article:tag","content":"道氏理论"}],["meta",{"property":"article:published_time","content":"2024-01-17T00:00:00.000Z"}],["meta",{"property":"article:modified_time","content":"2024-02-04T15:27:55.000Z"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"道氏理论四\\",\\"image\\":[\\"\\"],\\"datePublished\\":\\"2024-01-17T00:00:00.000Z\\",\\"dateModified\\":\\"2024-02-04T15:27:55.000Z\\",\\"author\\":[{\\"@type\\":\\"Person\\",\\"name\\":\\"Mr.G\\",\\"url\\":\\"https://mister-hope.com\\"}]}"]]},"headers":[{"level":2,"title":"双重顶和双重底","slug":"双重顶和双重底","link":"#双重顶和双重底","children":[]},{"level":2,"title":"论个股","slug":"论个股","link":"#论个股","children":[]},{"level":2,"title":"论投机","slug":"论投机","link":"#论投机","children":[]},{"level":2,"title":"论股市哲学","slug":"论股市哲学","link":"#论股市哲学","children":[]}],"git":{"createdTime":1707060475000,"updatedTime":1707060475000,"contributors":[{"name":"gm-hacker","email":"gm-hacker@qq.com","commits":1}]},"readingTime":{"minutes":34.4,"words":10320},"filePathRelative":"证券交易/道氏理论（天津社科版）/04-道氏理论四.md","localizedDate":"2024年1月17日","excerpt":"<h1> 道氏理论四</h1>\\n<h2> 双重顶和双重底</h2>\\n<p>双重顶和双重底形态，对于判断股票价格走势参考意义不大。实践表明它们时常会给人假象。</p>\\n<p>汉密尔顿曾经多次指出，根据双重顶或者双重底形态推断市场意义不大。一个有意思的疑问是，到底是谁告诉人们双重顶和双重底形态是道氏理论不可分割的一部分。这一观点甚至在人们心中根深蒂固。</p>\\n<p>每当接近前期高点或低点，市场上总是充斥着双重顶和双重底形态相关的评论文章，其预测结论注定一无是处。那些文章通常冠以这样的标签：根据道氏理论，假如工业股指数形成双重顶形态，等等。道氏理论的研究者无人不知，单靠一种价格指数得出的结论注定无效。同时，两种指数同时形成双重顶和双重底形态非常罕见，即便是同时出现也纯属巧合。细数一下三十五年以来重要的次级运动，不难发现以双重顶和双重底为标志结束的情况少之又少。</p>","autoDesc":true}');export{e as data};
